    private static void LogRequestHeaders(HttpRequest req, ILogger log)
    {
        log.LogInformation("Request Headers:");
        foreach (var header in req.Headers)
        {
            if (header.Key.ToLower().Contains("authorization") || 
                header.Key.ToLower().Contains("token") || 
                header.Key.ToLower().Contains("auth"))
            {
                log.LogInformation($"  {header.Key}: [REDACTED]");
            }
            else
            {
                log.LogInformation($"  {header.Key}: {header.Value}");
            }
        }
    }
    
    private static void LogUserContext(HttpRequest req, ILogger log)
    {
        try
        {
            var userId = req.Headers["X-User-ID"].FirstOrDefault();
            var userEmail = req.Headers["X-User-Email"].FirstOrDefault();
            var userRole = req.Headers["X-User-Role"].FirstOrDefault();
            
            if (!string.IsNullOrEmpty(userId))
                log.LogInformation($"User ID: {userId}");
            if (!string.IsNullOrEmpty(userEmail))
                log.LogInformation($"User Email: {userEmail}");
            if (!string.IsNullOrEmpty(userRole))
                log.LogInformation($"User Role: {userRole}");
        }
        catch (Exception ex)
        {
            log.LogWarning($"Failed to log user context: {ex.Message}");
        }
    }
    
    private static async Task ProcessDatabaseQuery(ILogger log, string requestBody)
    {
        try
        {
            var queryData = JsonConvert.DeserializeObject<Dictionary<string, object>>(requestBody);
            string query = queryData?.GetValueOrDefault("query")?.ToString();
            var parameters = queryData?.GetValueOrDefault("parameters") as Dictionary<string, object>;
            
            if (!string.IsNullOrEmpty(query))
            {
                log.LogInformation($"Database Query: {query}");
                
                if (parameters != null && parameters.Count > 0)
                {
                    log.LogInformation("Query Parameters:");
                    foreach (var param in parameters)
                    {
                        log.LogInformation($"  {param.Key}: {param.Value}");
                    }
                }
                
                // Simulate database execution
                await ExecuteDatabaseQuery(query, parameters, log);
            }
        }
        catch (Exception ex)
        {
            log.LogError($"Database processing error: {ex.Message}");
        }
    }
    
    private static async Task ExecuteDatabaseQuery(string query, Dictionary<string, object> parameters, ILogger log)
    {
        // This is a simulation - actual implementation would connect to database
        await Task.Delay(100);
        
        log.LogInformation("Executing database query simulation");
        log.LogInformation($"Query: {query}");
        log.LogInformation($"Parameters: {JsonConvert.SerializeObject(parameters)}");
    }
    
    private static void LogExceptionDetails(Exception ex, ILogger log)
    {
        var sb = new StringBuilder();
        sb.AppendLine("=== FULL EXCEPTION DETAILS ===");
        sb.AppendLine($"Exception Type: {ex.GetType().FullName}");
        sb.AppendLine($"Exception Message: {ex.Message}");
        sb.AppendLine($"Exception StackTrace: {ex.StackTrace}");
        sb.AppendLine($"Exception Source: {ex.Source}");
        sb.AppendLine($"Exception TargetSite: {ex.TargetSite?.Name}");
        
        if (ex.Data.Count > 0)
        {
            sb.AppendLine("Exception Data:");
            foreach (var key in ex.Data.Keys)
            {
                sb.AppendLine($"  {key}: {ex.Data[key]}");
            }
        }
        
        if (ex.InnerException != null)
        {
            sb.AppendLine("=== INNER EXCEPTION ===");
            sb.AppendLine($"Inner Exception Type: {ex.InnerException.GetType().FullName}");
            sb.AppendLine($"Inner Exception Message: {ex.InnerException.Message}");
            sb.AppendLine($"Inner Exception StackTrace: {ex.InnerException.StackTrace}");
        }
        
        log.LogError(sb.ToString());
    }
